"use client";

import { motion, useTransform, MotionValue } from "framer-motion";

interface Props {
  scrollYProgress: MotionValue<number>;
}

const RANGE_START = 0.13;
const RANGE_END = 0.28;

const logos = [
  { name: "boAt", src: "data:image/png;base64," },
  { name: "Astrotalk", src: "data:image/png;base64," },
  { name: "BeatO", src: "data:image/png;base64," },
  { name: "Amthor", src: "data:image/png;base64," },
  { name: "Responsive", src: "data:image/png;base64," },
  { name: "SVERVE", src: "data:image/png;base64," },
  { name: "Super Kicks", src: "data:image/png;base64," },
  { name: "True Colors", src: "data:image/png;base64," },
  { name: "Threads & Blocks", src: "data:image/png;base64," },
  { name: "Rangat", src: "data:image/png;base64," }
];

export default function ScenePaintingZoom({ scrollYProgress }: Props) {
  const sceneOpacity = useTransform(
    scrollYProgress,
    [RANGE_START, RANGE_START + 0.02, RANGE_END - 0.02, RANGE_END],
    [0, 1, 1, 0]
  );

  const headerOpacity = useTransform(
    scrollYProgress,
    [RANGE_START, RANGE_START + 0.04],
    [0, 1]
  );

  const gridOpacity = useTransform(
    scrollYProgress,
    [RANGE_START + 0.02, RANGE_START + 0.08],
    [0, 1]
  );

  const textOpacity = useTransform(
    scrollYProgress,
    [RANGE_END - 0.08, RANGE_END - 0.04],
    [0, 1]
  );

  return (
    <section
      style={{ height: "100vh" }}
      className="sticky top-0 overflow-hidden flex items-center justify-center"
      aria-label="Brands"
    >
      <motion.div
        className="absolute inset-0 bg-[#6D001A]"
        style={{ opacity: sceneOpacity }}
      />

      <motion.div
        className="relative z-10 w-full max-w-6xl px-[6vw]"
        style={{ opacity: sceneOpacity }}
      >
        <motion.p
          className="font-space-mono text-[#ffffff] text-xs tracking-widest uppercase mb-3 text-center"
          style={{ opacity: headerOpacity }}
        >
          Brands That Wanted to Enhanccee
        </motion.p>

        <motion.div
          className="grid grid-cols-5 gap-4"
          style={{ opacity: gridOpacity }}
        >
          {logos.map((logo, i) => (
            <motion.div
              key={i}
              className="flex flex-col items-center gap-2"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.07 }}
            >
              <div
                className="w-full flex items-center justify-center rounded-lg border border-[#00000033]"
                style={{
                  background: "rgba(0,0,0,0.3)",
                  padding: "12px",
                  height: "90px",
                }}
              >
                <img
                  src={logo.src}
                  alt={logo.name}
                  style={{ maxWidth: "100%", maxHeight: "66px", objectFit: "contain" }}
                />
              </div>
              <p
                className="font-space-mono text-[#f0c8d4] text-center"
                style={{ fontSize: "clamp(0.45rem, 0.7vw, 0.6rem)" }}
              >
                {logo.name}
              </p>
            </motion.div>
          ))}
        </motion.div>

        <motion.p
          className="font-cormorant italic text-[#f0c8d4] text-center mt-8"
          style={{
            fontSize: "clamp(0.9rem, 1.6vw, 1.2rem)",
            opacity: textOpacity,
          }}
        >
          Brands that trusted us to grow their digital presence.
        </motion.p>
      </motion.div>
    </section>
  );
}
